from math import sqrtprime_list=[]def is_prime(n):    if n <= 1:        return False    for i in range(2, int(sqrt(n))+1):        if n % i == 0:            return False    return Truedef prime_sum(n):    sum = 0    for i in range(2, n+1):        if is_prime(i):            sum += i            prime_list.append(i)    return sumresult = prime_sum(100)print(prime_list)print(result)